+  /**
+   * Execute hooks for an event.
+   */
+  async execute(event: HookEvent, data: unknown, source?: string): Promise<HookResult[]> {
+    const entries = this.hooks.get(event);
+    if (!entries || entries.length === 0) {
+      return [];
+    }
