+// ============================================================================
+// Command Security
+// ============================================================================
+
+const ALLOWED_COMMANDS = new Set([
+  'npm', 'npx', 'node', 'git', 'tsc', 'vitest', 'jest',
+  'prettier', 'eslint', 'ls', 'cat', 'grep', 'find',
