+const BLOCKED_COMMANDS = new Set([
+  'rm', 'del', 'format', 'dd', 'mkfs', 'fdisk',
+  'shutdown', 'reboot', 'poweroff', 'halt',
+  'passwd', 'sudo', 'su', 'chmod', 'chown',
