+      if (memMB > config.maxMemoryMB) {
+        violations.push(`Memory usage ${memMB.toFixed(1)}MB exceeds limit ${config.maxMemoryMB}MB`);
+      }
+
+      return {
+        ok: violations.length === 0,
+        violations,
+      };
+    },
