+      const check = this.check();
+      if (!check.ok) {
+        throw new Error(`Resource limits exceeded: ${check.violations.join(', ')}`);
+      }
+
+      return Promise.race([
+        fn(),
+        new Promise<never>((_, reject) =>
+          setTimeout(() => reject(new Error('Execution time limit exceeded')), config.maxExecutionTime)
+        ),
+      ]);
+    },
+  };
