+
+  // Error sanitization
+  sanitizeError,
+  sanitizeErrorMessage,
+
+  // Rate limiting
+  createRateLimiter,
+
+  // Crypto
+  generateSecureId,
+  generateSecureToken,
+  hashString,
+  constantTimeCompare,
+
+  // Resource limits
+  createResourceLimiter,
+};

