+      this._status = 'error';
+      this._currentTask = undefined;
+
+      return {
+        workerId: this.id,
+        taskId: task.id,
+        taskType: task.type,
+        success: false,
+        error: error instanceof Error ? error.message : String(error),
+        duration,
+      };
+    }
+  }
+
+  private async executeTask(task: WorkerTask): Promise<{
+    output: unknown;
+    tokensUsed?: number;
+    metadata?: Record<string, unknown>;
