+  shutdown(): Promise<void>;
+}
+
+export interface PoolMetrics {
+  totalWorkers: number;
+  activeWorkers: number;
+  idleWorkers: number;
+  queuedTasks: number;
+  completedTasks: number;
+  failedTasks: number;
+  avgTaskDuration: number;
+}
